previewCss:
.darma-loader-darma-custom-220 {
  color: var(--loader-color, #2563eb);
  width: 90px;
  height: 14px;
  background: repeating-linear-gradient(90deg,currentColor 0 calc(25% - 5px),#0000 0 25%) left/calc(4*100%/3) 100%;
  animation: darma-loader-darma-custom-220-l1 0.5s infinite linear;
}
@keyframes darma-loader-darma-custom-220-l1 {
    100% {background-position: right}
}

